# dual explorer-H1 · S16-T1-A-E2
import pandas as pd
policy = {"a": "required", "b": "optional"}
df = pd.DataFrame({"a": [1, None], "b": [None, 2]})
viol = {}
for col, kind in policy.items():
    if kind != "required":
        continue
    n = int(df[col].isna().sum())
    if n > 0:
        viol[col] = n
h1_out = viol
print(h1_out)
